try {
  const body = $input.first().json.body;
  if (!body) throw new Error('Request body is empty');
  const slug = body.slug || '';
  if (!slug || slug.trim().length < 1) throw new Error('Spoke slug is required');
  const clean = slug.trim().toLowerCase().replace(/[^a-z0-9-]/g, '-');
  return [{ json: { slug: clean } }];
} catch(e) {
  throw new Error(e.message);
}

const results = $input.all();
const slug = $('Validate Slug').first().json.slug;

if (results && results.length > 0 && results[0].json.slug) {
  return [{ json: { found: true, slug: slug, spoke: results[0].json } }];
}

return [{ json: { found: false, slug: slug } }];

