try {
  const aiResponse = $input.first().json;
  const slug = $('Validate Slug').first().json.slug;
  const content = aiResponse.message && aiResponse.message.content ? aiResponse.message.content : '';
  const clean = content.replace(/```json/g, '').replace(/```/g, '').trim();
  const spoke = JSON.parse(clean);
  if (!spoke || typeof spoke !== 'object') throw new Error('Invalid response');
  spoke.slug = spoke.slug || slug;
  spoke.from_ai = true;
  return [{ json: { success: true, spoke: spoke, from_ai: true } }];
} catch(e) {
  throw new Error('Failed to parse AI response: ' + e.message);
}

// Use DB spoke data directly
const spoke = $input.first().json.spoke;
return [{ json: { success: true, spoke: spoke, from_ai: false } }];
